      )
    }
  }

  const mailDetailsDrafts = await this.loadInChunks(
    MailDetailsDraftTypeRef,
    listId,
    ids,
    providedOwnerEncSessionKeys  // Add this parameter
  )
  result.push(
    ...mailDetailsDrafts.map((draftDetails) => {
      const mail = assertNotNull(mailDetailsDraftMails.find((m) => isSameId(m.mailDetailsDraft, draftDetails._id)))
      return MailWrapper.details(mail, draftDetails.details)
    }),
  )
}
```

### 3. Update loadInChunks Signature

**Current Code (Line 780-791):**
```typescript
private loadInChunks<T extends SomeEntity>(
  typeRef: TypeRef<T>,
  listId: Id | null,
  ids: Id[]
): Promise<T[]> {
  const byChunk = splitInChunks(ENTITY_INDEXER_CHUNK, ids)
  return promiseMap(
    byChunk,
    (chunk) => {
      return chunk.length > 0 ? this._entity.loadMultiple(typeRef, listId, chunk) : Promise.resolve([])
    },
    {
      concurrency: 2,
    },
  ).then((entityResults) => entityResults.flat())
}
```

**Fixed Code:**
```typescript
private loadInChunks<T extends SomeEntity>(
  typeRef: TypeRef<T>,
  listId: Id | null,
  ids: Id[],
  providedOwnerEncSessionKeys?: Map<Id, Uint8Array>  // Add this parameter
): Promise<T[]> {
  const byChunk = splitInChunks(ENTITY_INDEXER_CHUNK, ids)
  return promiseMap(
    byChunk,
    (chunk) => {
      return chunk.length > 0
        ? this._entity.loadMultiple(typeRef, listId, chunk, providedOwnerEncSessionKeys)  // Pass it through
        : Promise.resolve([])
    },
    {
      concurrency: 2,
    },
  ).then((entityResults) => entityResults.flat())
}
```

### 4. Update Other loadInChunks Calls

Check for other calls to `loadInChunks` that don't need session keys:

**Line 720 (MailBody loading):**
```typescript
